package org.apache.commons.csv;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;

public class CSVFormatTest {

    @Test
    public void testGetHeader() {
        // Given
        String[] expectedHeader = {"Header1", "Header2", "Header3"};
        CSVFormat csvFormat = createCSVFormat();
        setHeader(csvFormat, expectedHeader);

        // When
        String[] actualHeader = csvFormat.getHeader();

        // Then
        assertArrayEquals(expectedHeader, actualHeader);
    }

    private CSVFormat createCSVFormat() {
        try {
            Field constructor = CSVFormat.class.getDeclaredField("DEFAULT");
            constructor.setAccessible(true);
            return (CSVFormat) constructor.get(null);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            e.printStackTrace();
            return null;
        }
    }

    private void setHeader(CSVFormat csvFormat, String[] header) {
        try {
            Field field = CSVFormat.class.getDeclaredField("header");
            field.setAccessible(true);
            field.set(csvFormat, header);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            e.printStackTrace();
        }
    }
}
